import { random, range } from 'lodash';
import { normalize } from './utils';
import './reset.css';
import './styles.css';

const btn = document.querySelector('.particleButton');

const MIN_DISTANCE = 32;
const MAX_DISTANCE = 64;
const MIN_FADE_DURATION = 1000 - 500;
const MAX_FADE_DURATION = 1000 + 500;
const MAX_FADE_DELAY = 500;
const MAX_FADE_ADJUST = 200;
const NUM_OF_PARTICLES = 15;
const PARTICLE_DELAY = 150;

btn.style.setProperty(
  '--pop-circle-duration',
  PARTICLE_DELAY + 'ms'
);

btn.addEventListener('click', () => {
  btn.classList.toggle('liked');

  const isLiked = btn.classList.contains('liked');
  if (!isLiked) {
    return;
  }

  const isMotionEnabled = window.matchMedia(
    '(prefers-reduced-motion: no-preference)'
  ).matches;
  if (!isMotionEnabled) {
    return;
  }

  const particles = [];
  range(NUM_OF_PARTICLES).forEach((index) => {
    const particle = document.createElement('span');
    particle.classList.add('particle');

    // Apply the start color as an inline style:
    particle.style.backgroundColor =
      `hsl(${random(0, 360)}deg 90% 85%)`;

    // Apply the destination hue with a CSS variable.
    // Right now, this is a flat value, but maybe it
    // should be dynamic / randomized?
    particle.style.setProperty(
      '--hue-rotation',
      '720deg'
    );

    //
    //
    //
    // The rest of this stuff is all the same.
    let angle = normalize(index, 0, NUM_OF_PARTICLES, 0, 360);
    angle += random(-40, 40);

    const distance = random(MIN_DISTANCE, MAX_DISTANCE);

    particle.style.setProperty('--angle', angle + 'deg');
    particle.style.setProperty('--distance', distance + 'px');

    particle.style.setProperty(
      '--fade-duration',
      normalize(
        distance,
        MIN_DISTANCE,
        MAX_DISTANCE,
        MIN_FADE_DURATION,
        MAX_FADE_DURATION
      ) +
        random(-200, 200) +
        'ms'
    );
    particle.style.setProperty(
      '--fade-delay',
      normalize(distance, MIN_DISTANCE, MAX_DISTANCE, 0, MAX_FADE_DELAY) +
        random(0, MAX_FADE_ADJUST) +
        'ms'
    );
    particle.style.setProperty(
      '--pop-duration',
      normalize(distance, MIN_DISTANCE, MAX_DISTANCE, 400, 800) +
        random(-200, 200) +
        'ms'
    );
    particle.style.setProperty(
      '--size',
      random(9, 15) + 'px'
    );

    particles.push(particle);
  });

  window.setTimeout(() => {
    particles.forEach((particle) => {
      btn.appendChild(particle);
    });
  }, PARTICLE_DELAY);

  const cleanupDuration =
    MAX_FADE_DURATION +
    MAX_FADE_DELAY +
    MAX_FADE_ADJUST +
    PARTICLE_DELAY +
    200;

  window.setTimeout(
    () => {
      particles.forEach((particle) => {
        particle.remove();
      });
    },
    cleanupDuration
  );
});

export const normalize = (
  number,
  currentScaleMin,
  currentScaleMax,
  newScaleMin = 0,
  newScaleMax = 1
) => {
  // First, normalize the value between 0 and 1.
  const standardNormalization =
    (number - currentScaleMin) / (currentScaleMax - currentScaleMin);

  // Next, transpose that value to our desired scale.
  return (
    (newScaleMax - newScaleMin) * standardNormalization + newScaleMin
  );
};

export const convertDegreesToRadians = (angle) => (angle * Math.PI) / 180;

export const convertPolarToCartesian = (angle, distance) => {
  const angleInRadians = convertDegreesToRadians(angle);
  const x = Math.cos(angleInRadians) * distance;
  const y = Math.sin(angleInRadians) * distance;

  return [x, y];
};

